$function$;
COMMENT ON FUNCTION document.charte_create(text,text,text,text,text,text,text,text,jsonb,text,text,text,text,text,text,text,text,text,text[],text,text[],text[],text[],jsonb,jsonb) IS 'Create a design system charte with 6 mandatory colors, fonts, spacing, voice, rules';

