CREATE OR REPLACE FUNCTION document.layout_check(p_html text, p_width numeric, p_height numeric)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_overflows text[] := ARRAY[]::text[];
  v_w_match text[];
  v_h_match text[];
  v_w numeric;
  v_h numeric;
  r record;
BEGIN
  FOR r IN
    SELECT m[1] AS data_id, m[2] AS style_val
    FROM regexp_matches(p_html, 'data-id="([^"]*)"[^>]*style="([^"]*)"', 'g') AS m
  LOOP
    -- Extract width
    v_w_match := regexp_match(r.style_val, 'width:\s*([0-9.]+)\s*mm');
    v_w := CASE WHEN v_w_match IS NOT NULL THEN v_w_match[1]::numeric ELSE NULL END;

    -- Extract height
    v_h_match := regexp_match(r.style_val, 'height:\s*([0-9.]+)\s*mm');
    v_h := CASE WHEN v_h_match IS NOT NULL THEN v_h_match[1]::numeric ELSE NULL END;

    IF v_w IS NOT NULL AND v_w > p_width THEN
      v_overflows := v_overflows || format('[%s] width %smm > canvas %smm', r.data_id, v_w, p_width);
    END IF;
    IF v_h IS NOT NULL AND v_h > p_height THEN
      v_overflows := v_overflows || format('[%s] height %smm > canvas %smm', r.data_id, v_h, p_height);
    END IF;
  END LOOP;

  IF cardinality(v_overflows) = 0 THEN
    RETURN NULL;
  END IF;

  RETURN 'Layout overflows:' || chr(10) || array_to_string(v_overflows, chr(10));
END;
$function$;
COMMENT ON FUNCTION document.layout_check(text,numeric,numeric) IS 'Detect elements overflowing canvas dimensions';

CREATE OR REPLACE FUNCTION document.library_add_asset(p_library_id text, p_asset_id uuid, p_role text DEFAULT NULL::text, p_context text DEFAULT NULL::text, p_sort_order integer DEFAULT 0)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO document.library_asset (library_id, asset_id, role, context, sort_order)
  VALUES (p_library_id, p_asset_id, p_role, p_context, p_sort_order)
  ON CONFLICT (library_id, asset_id) DO UPDATE SET
    role = EXCLUDED.role,
    context = EXCLUDED.context,
    sort_order = EXCLUDED.sort_order;
END;
$function$;
COMMENT ON FUNCTION document.library_add_asset(text,uuid,text,text,integer) IS 'Add or update an asset in a library with role and context';

CREATE OR REPLACE FUNCTION document.library_create(p_name text, p_description text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id text;
BEGIN
  INSERT INTO document.library (name, description)
  VALUES (p_name, p_description)
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$function$;
COMMENT ON FUNCTION document.library_create(text,text) IS 'Create a curated asset library for document composition';

CREATE OR REPLACE FUNCTION document.library_delete(p_name text)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_deleted int;
BEGIN
  DELETE FROM document.library WHERE name = p_name AND tenant_id = current_setting('app.tenant_id', true);
  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted > 0;
END;
$function$;
COMMENT ON FUNCTION document.library_delete(text) IS 'Delete a library by name (CASCADE library_asset)';

CREATE OR REPLACE FUNCTION document.library_list()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_result jsonb := '[]'::jsonb;
  r record;
BEGIN
  FOR r IN
    SELECT l.id, l.name, l.description,
           (SELECT count(*) FROM document.library_asset la WHERE la.library_id = l.id) AS asset_cnt,
           l.created_at
    FROM document.library l
    WHERE l.tenant_id = current_setting('app.tenant_id', true)
    ORDER BY l.name
  LOOP
    v_result := v_result || jsonb_build_object(
      'id', r.id, 'name', r.name, 'description', r.description,
      'assets', r.asset_cnt, 'created_at', r.created_at
    );
  END LOOP;
  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION document.library_list() IS 'List all libraries for current tenant with asset count';

CREATE OR REPLACE FUNCTION document.library_load(p_library_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_lib document.library;
  v_assets jsonb := '[]'::jsonb;
  r record;
BEGIN
  SELECT * INTO v_lib FROM document.library WHERE id = p_library_id AND tenant_id = current_setting('app.tenant_id', true);
  IF v_lib IS NULL THEN RETURN NULL; END IF;

  FOR r IN
    SELECT a.id, a.filename, a.title, a.description, a.tags, a.width, a.height, a.mime_type, a.path,
           la.role, la.context, la.sort_order
    FROM document.library_asset la
    JOIN asset.asset a ON a.id = la.asset_id
    WHERE la.library_id = p_library_id
    ORDER BY la.sort_order, a.filename
  LOOP
    v_assets := v_assets || jsonb_build_object(
      'id', r.id, 'filename', r.filename, 'title', r.title,
      'description', r.description, 'tags', r.tags,
      'width', r.width, 'height', r.height, 'mime_type', r.mime_type, 'path', r.path,
      'role', r.role, 'context', r.context, 'sort_order', r.sort_order
    );
  END LOOP;

  RETURN jsonb_build_object(
    'id', v_lib.id,
    'name', v_lib.name,
    'description', v_lib.description,
    'assets', v_assets
  );
END;
$function$;
COMMENT ON FUNCTION document.library_load(text) IS 'Load library with all assets (metadata from asset.asset)';

CREATE OR REPLACE FUNCTION document.doc_load(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_d document.document;
  v_css text;
  v_pages jsonb := '[]'::jsonb;
  v_library jsonb;
  r record;
BEGIN
  SELECT * INTO v_d FROM document.document WHERE id = p_id AND tenant_id = current_setting('app.tenant_id', true);
  IF v_d IS NULL THEN RETURN NULL; END IF;

  IF v_d.charte_id IS NOT NULL THEN
    v_css := document.charte_tokens_to_css(v_d.charte_id);
  END IF;

  IF v_d.library_id IS NOT NULL THEN
    v_library := document.library_load(v_d.library_id);
  END IF;

  FOR r IN
    SELECT page_index, name, html, format, orientation, width, height, bg, text_margin
    FROM document.page WHERE doc_id = p_id ORDER BY page_index
  LOOP
    v_pages := v_pages || jsonb_build_object(
      'page_index', r.page_index,
      'name', r.name,
      'html', r.html,
      'format', r.format,
      'width', r.width,
      'height', r.height,
      'bg', r.bg
    );
  END LOOP;

  RETURN jsonb_build_object(
    'id', v_d.id,
    'name', v_d.name,
    'category', v_d.category,
    'format', v_d.format,
    'orientation', v_d.orientation,
    'width', v_d.width,
    'height', v_d.height,
    'bg', v_d.bg,
    'text_margin', v_d.text_margin,
    'status', v_d.status,
    'charte_id', v_d.charte_id,
    'charte_css', v_css,
    'library_id', v_d.library_id,
    'library', v_library,
    'pages', v_pages,
    'active_page', v_d.active_page,
    'rating', v_d.rating,
    'design_notes', v_d.design_notes
  );
END;
$function$;
COMMENT ON FUNCTION document.doc_load(text) IS 'Load document with all pages, charte CSS, and library assets';

CREATE OR REPLACE FUNCTION document.library_remove_asset(p_library_id text, p_asset_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_deleted int;
BEGIN
  DELETE FROM document.library_asset WHERE library_id = p_library_id AND asset_id = p_asset_id;
  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted > 0;
END;
$function$;
COMMENT ON FUNCTION document.library_remove_asset(text,uuid) IS 'Remove an asset from a library';

CREATE OR REPLACE FUNCTION document.nav_items()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_array(
    jsonb_build_object('href', '/', 'label', pgv.t('document.nav_documents'), 'icon', 'file-text'),
    jsonb_build_object('href', '/chartes', 'label', pgv.t('document.nav_chartes'), 'icon', 'palette'),
    jsonb_build_object('href', '/libraries', 'label', pgv.t('document.nav_libraries'), 'icon', 'image')
  );
$function$;
COMMENT ON FUNCTION document.nav_items() IS 'Navigation items for document module (i18n)';

CREATE OR REPLACE FUNCTION document.normalize_color(p_raw text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_raw text;
  v_m text[];
  v_r int; v_g int; v_b int;
BEGIN
  v_raw := lower(trim(p_raw));

  -- #rrggbb
  IF v_raw ~ '^#[0-9a-f]{6}$' THEN
    RETURN v_raw;
  END IF;

  -- #rgb → #rrggbb
  IF v_raw ~ '^#[0-9a-f]{3}$' THEN
    RETURN '#' || substr(v_raw,2,1) || substr(v_raw,2,1)
             || substr(v_raw,3,1) || substr(v_raw,3,1)
             || substr(v_raw,4,1) || substr(v_raw,4,1);
  END IF;

  -- rgb(r, g, b)
  v_m := regexp_match(v_raw, '^rgb\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)\s*\)$');
  IF v_m IS NOT NULL THEN
    v_r := v_m[1]::int;
    v_g := v_m[2]::int;
    v_b := v_m[3]::int;
    IF v_r BETWEEN 0 AND 255 AND v_g BETWEEN 0 AND 255 AND v_b BETWEEN 0 AND 255 THEN
      RETURN '#' || lpad(to_hex(v_r), 2, '0') || lpad(to_hex(v_g), 2, '0') || lpad(to_hex(v_b), 2, '0');
    END IF;
  END IF;

  RETURN NULL;
END;
$function$;
COMMENT ON FUNCTION document.normalize_color(text) IS 'Normalize CSS color to #rrggbb lowercase (hex 3/6, rgb())';

CREATE OR REPLACE FUNCTION document.page_add(p_doc_id text, p_name text DEFAULT NULL::text, p_html text DEFAULT ''::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_idx integer;
BEGIN
  SELECT COALESCE(MAX(page_index), -1) + 1 INTO v_idx FROM document.page WHERE doc_id = p_doc_id;

  INSERT INTO document.page (doc_id, page_index, name, html)
  VALUES (p_doc_id, v_idx, COALESCE(p_name, 'Page ' || (v_idx + 1)::text), COALESCE(p_html, ''));

  RETURN v_idx;
END;
$function$;
COMMENT ON FUNCTION document.page_add(text,text,text) IS 'Add a page to a document (appended at end)';

CREATE OR REPLACE FUNCTION document.page_remove(p_doc_id text, p_page_index integer)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total int;
  v_active int;
BEGIN
  SELECT count(*)::int INTO v_total FROM document.page WHERE doc_id = p_doc_id;
  IF v_total <= 1 THEN
    RAISE EXCEPTION 'Cannot remove the last page';
  END IF;

  DELETE FROM document.page WHERE doc_id = p_doc_id AND page_index = p_page_index;
  IF NOT FOUND THEN RETURN false; END IF;

  -- Renumber pages after the removed one
  UPDATE document.page SET page_index = page_index - 1
  WHERE doc_id = p_doc_id AND page_index > p_page_index;

  -- Adjust active_page if needed
  SELECT active_page INTO v_active FROM document.document WHERE id = p_doc_id;
  IF v_active >= v_total - 1 THEN
    UPDATE document.document SET active_page = greatest(0, v_total - 2) WHERE id = p_doc_id;
  ELSIF v_active > p_page_index THEN
    UPDATE document.document SET active_page = v_active - 1 WHERE id = p_doc_id;
  END IF;

  RETURN true;
END;
$function$;
COMMENT ON FUNCTION document.page_remove(text,integer) IS 'Remove a page and renumber subsequent pages';

CREATE OR REPLACE FUNCTION document.page_set_html(p_doc_id text, p_page_index integer, p_html text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old_html text;
  v_version int;
  v_count int;
BEGIN
  -- Get current HTML
  SELECT html INTO v_old_html FROM document.page WHERE doc_id = p_doc_id AND page_index = p_page_index;
  IF v_old_html IS NULL THEN
    RAISE EXCEPTION 'Page not found: doc=% page=%', p_doc_id, p_page_index;
  END IF;

  -- Save revision (if there's actual content to save)
  IF v_old_html != '' THEN
    SELECT COALESCE(MAX(version), 0) + 1 INTO v_version
    FROM document.page_revision WHERE doc_id = p_doc_id AND page_index = p_page_index;

    INSERT INTO document.page_revision (doc_id, page_index, version, html)
    VALUES (p_doc_id, p_page_index, v_version, v_old_html);
  END IF;

  -- Update HTML
  UPDATE document.page SET html = p_html WHERE doc_id = p_doc_id AND page_index = p_page_index;

  -- Update document timestamp
  UPDATE document.document SET updated_at = now() WHERE id = p_doc_id;

  -- Count data-id elements
  SELECT count(*)::int INTO v_count FROM regexp_matches(p_html, 'data-id="[^"]*"', 'g');

  RETURN v_count;
END;
$function$;
COMMENT ON FUNCTION document.page_set_html(text,integer,text) IS 'Set page HTML, save previous version to page_revision';

CREATE OR REPLACE FUNCTION document.style_merge(p_existing text, p_new text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_props jsonb := '{}'::jsonb;
  v_pair text;
  v_key text;
  v_val text;
  v_result text := '';
  v_k text;
  v_v text;
BEGIN
  -- Parse existing
  IF p_existing IS NOT NULL AND p_existing != '' THEN
    FOREACH v_pair IN ARRAY string_to_array(p_existing, ';')
    LOOP
      v_pair := trim(v_pair);
      IF v_pair = '' THEN CONTINUE; END IF;
      v_key := trim(split_part(v_pair, ':', 1));
      v_val := trim(substring(v_pair from position(':' in v_pair) + 1));
      IF v_key != '' AND v_val != '' THEN
        v_props := v_props || jsonb_build_object(v_key, v_val);
      END IF;
    END LOOP;
  END IF;

  -- Merge new (overwrite)
  IF p_new IS NOT NULL AND p_new != '' THEN
    FOREACH v_pair IN ARRAY string_to_array(p_new, ';')
    LOOP
      v_pair := trim(v_pair);
      IF v_pair = '' THEN CONTINUE; END IF;
      v_key := trim(split_part(v_pair, ':', 1));
      v_val := trim(substring(v_pair from position(':' in v_pair) + 1));
      IF v_key != '' AND v_val != '' THEN
        v_props := v_props || jsonb_build_object(v_key, v_val);
      END IF;
    END LOOP;
  END IF;

  -- Serialize
  FOR v_k, v_v IN SELECT key, value #>> '{}' FROM jsonb_each(v_props)
  LOOP
    IF v_result != '' THEN v_result := v_result || ';'; END IF;
    v_result := v_result || v_k || ':' || v_v;
  END LOOP;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION document.style_merge(text,text) IS 'Merge two CSS inline strings (last-write-wins per property)';

CREATE OR REPLACE FUNCTION document.xhtml_validate(p_html text)
 RETURNS boolean
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  RETURN xml_is_well_formed('<root>' || COALESCE(p_html, '') || '</root>');
END;
$function$;
COMMENT ON FUNCTION document.xhtml_validate(text) IS 'Check if HTML fragment is well-formed XML';

CREATE OR REPLACE FUNCTION document.xhtml_patch(p_html text, p_ops jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text := p_html;
  v_op jsonb;
  v_id text;
  v_marker text;
  v_pos int;
  v_tag_start int;
  v_tag_end int;
  v_close_pos int;
  v_tag_name text;
  v_old_style text;
  v_new_style text;
  v_style_str text;
  v_sk text;
  v_sv text;
  v_depth int;
  v_search_pos int;
  v_elem_start int;
  v_elem_end int;
  v_inner_start int;
  v_self_closing boolean;
BEGIN
  FOR v_op IN SELECT value FROM jsonb_array_elements(p_ops)
  LOOP
    v_id := v_op->>'id';
    v_marker := 'data-id="' || v_id || '"';
    v_pos := position(v_marker in v_html);
    IF v_pos = 0 THEN CONTINUE; END IF;

    -- Find the opening tag boundaries: scan backwards for '<'
    v_tag_start := v_pos;
    WHILE v_tag_start > 1 AND substr(v_html, v_tag_start, 1) != '<' LOOP
      v_tag_start := v_tag_start - 1;
    END LOOP;

    -- Extract tag name
    v_tag_name := (regexp_match(substr(v_html, v_tag_start), '^<([a-zA-Z][a-zA-Z0-9]*)'))[1];

    -- Find end of opening tag
    v_tag_end := position('>' in substr(v_html, v_tag_start)) + v_tag_start - 1;

    -- Check self-closing
    v_self_closing := substr(v_html, v_tag_end - 1, 2) = '/>';

    IF NOT v_self_closing THEN
      -- Find matching closing tag (handle nesting)
      v_inner_start := v_tag_end + 1;
      v_depth := 1;
      v_search_pos := v_inner_start;
      WHILE v_depth > 0 AND v_search_pos <= length(v_html) LOOP
        -- Look for next opening or closing tag of same name
        v_close_pos := position('</' || v_tag_name in substr(v_html, v_search_pos));
        IF v_close_pos = 0 THEN EXIT; END IF;
        v_close_pos := v_close_pos + v_search_pos - 1;

        -- Check for nested opening tags between search_pos and close_pos
        DECLARE
          v_nested_pos int;
          v_scan int := v_search_pos;
        BEGIN
          LOOP
            v_nested_pos := position('<' || v_tag_name in substr(v_html, v_scan));
            IF v_nested_pos = 0 THEN EXIT; END IF;
            v_nested_pos := v_nested_pos + v_scan - 1;
            IF v_nested_pos >= v_close_pos THEN EXIT; END IF;
            -- Verify it's actually an opening tag (not </tag or part of another tag)
            IF substr(v_html, v_nested_pos + 1 + length(v_tag_name), 1) IN (' ', '>', '/') THEN
              v_depth := v_depth + 1;
            END IF;
            v_scan := v_nested_pos + 1;
          END LOOP;
        END;

        v_depth := v_depth - 1;
        IF v_depth = 0 THEN
          -- v_close_pos is the start of the closing tag
          v_elem_end := position('>' in substr(v_html, v_close_pos)) + v_close_pos; -- after '>'
        ELSE
          v_search_pos := v_close_pos + 1;
        END IF;
      END LOOP;
    ELSE
      v_inner_start := v_tag_end; -- no inner content
      v_elem_end := v_tag_end + 1;
    END IF;

    -- REMOVE
    IF (v_op->>'remove')::boolean IS TRUE THEN
      v_html := substr(v_html, 1, v_tag_start - 1) || substr(v_html, v_elem_end);
      CONTINUE;
    END IF;

    -- REPLACE (outer)
    IF v_op ? 'replace' THEN
      v_html := substr(v_html, 1, v_tag_start - 1) || (v_op->>'replace') || substr(v_html, v_elem_end);
      CONTINUE;
    END IF;

    -- STYLE merge
    IF v_op ? 'style' THEN
      -- Build new style string from op
      v_style_str := '';
      FOR v_sk, v_sv IN SELECT key, value #>> '{}' FROM jsonb_each(v_op->'style')
      LOOP
        IF v_style_str != '' THEN v_style_str := v_style_str || ';'; END IF;
        v_style_str := v_style_str || v_sk || ':' || v_sv;
      END LOOP;

      -- Extract existing style from opening tag
      DECLARE
        v_open_tag text := substr(v_html, v_tag_start, v_tag_end - v_tag_start + 1);
        v_style_match text[];
        v_new_tag text;
      BEGIN
        v_style_match := regexp_match(v_open_tag, 'style="([^"]*)"');
        IF v_style_match IS NOT NULL THEN
          v_old_style := v_style_match[1];
          v_new_style := document.style_merge(v_old_style, v_style_str);
          v_new_tag := regexp_replace(v_open_tag, 'style="[^"]*"', 'style="' || v_new_style || '"');
        ELSE
          -- No existing style, add it before the closing > or />
          IF v_self_closing THEN
            v_new_tag := regexp_replace(v_open_tag, '\s*/>', ' style="' || v_style_str || '"/>');
          ELSE
            v_new_tag := regexp_replace(v_open_tag, '>', ' style="' || v_style_str || '">');
          END IF;
        END IF;
        v_html := substr(v_html, 1, v_tag_start - 1) || v_new_tag || substr(v_html, v_tag_end + 1);

        -- Adjust positions after tag replacement
        v_tag_end := v_tag_start + length(v_new_tag) - 1;
        v_inner_start := v_tag_end + 1;
      END;
    END IF;

    -- CONTENT (innerHTML replacement)
    IF v_op ? 'content' AND NOT v_self_closing THEN
      -- Recalculate close position after potential style change
      v_close_pos := position('</' || v_tag_name in substr(v_html, v_inner_start));
      IF v_close_pos > 0 THEN
        v_close_pos := v_close_pos + v_inner_start - 1;
        v_html := substr(v_html, 1, v_inner_start - 1) || (v_op->>'content') || substr(v_html, v_close_pos);
      END IF;
    END IF;

    -- INSERT (beforeend = before closing tag)
    IF v_op ? 'insert' AND NOT v_self_closing THEN
      v_close_pos := position('</' || v_tag_name in substr(v_html, v_inner_start));
      IF v_close_pos > 0 THEN
        v_close_pos := v_close_pos + v_inner_start - 1;
        v_html := substr(v_html, 1, v_close_pos - 1) || (v_op->>'insert') || substr(v_html, v_close_pos);
      END IF;
    END IF;
  END LOOP;

  -- Validate result
  IF NOT document.xhtml_validate(v_html) THEN
    RAISE EXCEPTION 'xhtml_patch produced invalid XML';
  END IF;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION document.xhtml_patch(text,jsonb) IS 'Surgical XHTML patch by data-id: style merge, content replace, remove, insert, replace element';

GRANT USAGE ON SCHEMA document TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA document TO anon;
GRANT SELECT ON ALL TABLES IN SCHEMA document TO anon;
